// update the colorscheme definitions.  This is not done automatically.  You must
// manually update styles/colors.css via "pnpm run update-color-scheme" if you
// change anything (e.g., @cocalc/util/theme.ts) that impacts it.

const fs = require("fs");
const path = require("path");
const { COLORS } = require("@cocalc/util/theme");

const isObject = (a) => !!a && a.constructor === Object;

let colors_css =
  "/* DO NOT UPDATE THIS FILE -- autogenerated via 'pnpm run update-color-scheme' based on @cocalc/util/theme.ts */\n\n:root {\n";

function cssVariable(name) {
  return `--cocalc-${name.toLowerCase().replace(/_/g, "-")}`;
}

for (let c in COLORS) {
  // there are nested definitions
  const v = COLORS[c];
  if (isObject(v)) {
    for (let c2 in v) {
      const v2 = v[c2];
      colors_css += `  ${cssVariable(`COL_${c}_${c2}`)}: ${v2};\n`;
    }
  } else {
    colors_css += `  ${cssVariable(`COL_${c}`)}: ${v};\n`;
  }
}

colors_css += "}\n";

fs.writeFileSync(path.join("styles", "colors.css"), colors_css);
